use cudarc::driver::{CudaContext, DriverError, LaunchConfig};

pub fn execute_wiener_pipeline(data: &[f32]) -> Result<Vec<f32>, DriverError> {
    // 1. Initialize GPU (device 0)
    let ctx = CudaContext::new(0)?;

    // 2. Load PTX kernel generated by build.rs
    // include_bytes! injects binary directly into our Rust's executable
    let ptx = include_bytes!(concat!(env!("OUT_DIR"), "/wiener.ptx"));
    
    // Load module y and sotore in variable
    let module = ctx.load_module(ptx.to_vec())?;
    let f = module.get_func("wiener", "wiener_dummy").unwrap();

    let num_elements = data.len();

    // 3. Allocate GPU memory using context's default stream
    let stream = ctx.default_stream();
    let mut d_in = stream.alloc_zeros::<f32>(num_elements)?;
    let mut d_out = stream.alloc_zeros::<f32>(num_elements)?;

    // 4. Copy data (Host -> Device)
    stream.htod_sync_copy_into(data, &mut d_in)?;

    // 5. Configure Kernel grid (Grid / Block)
    let threads_per_block = 256;
    let blocks = (num_elements as u32 + threads_per_block - 1) / threads_per_block;
    let cfg = LaunchConfig {
        grid_dim: (blocks, 1, 1),
        block_dim: (threads_per_block, 1, 1),
        shared_mem_bytes: 0,
    };

    // 6. Run kernel using stream's builder
    unsafe { stream.launch_builder(&f).arg(&mut d_out).arg(&d_in).arg(num_elements as i32).launch(cfg) }?;

    // 7. Copy final result back (Device -> Host)
    let result = stream.sync_reclaim(d_out)?;

    Ok(result)
}
